3	const VALID_ITEM_TYPES = new Set(["sword", "amulet", "staff", "potion", "rune", "moonstone"]);
4	
5	const readStdin = async (): Promise<string> => {
6	  const chunks: Buffer[] = [];
7	  for await (const chunk of process.stdin) {
8	    chunks.push(chunk as Buffer);
9	  }
10	  return Buffer.concat(chunks).toString("utf8");
11	};
12	
13	const main = async (): Promise<void> => {
14	  const input = await readStdin();
15	  const scenario = JSON.parse(input);
16	
17	  for (const step of scenario.steps) {
18	    if (step.op === "quote") {
19	      for (const item of step.items) {
20	        if (!VALID_ITEM_TYPES.has(item.type)) {
21	          console.error(`unknown item type: ${item.type}`);
22	          process.exit(1);
23	        }
24	      }
25	    }
26	  }
27	
28	  console.log(JSON.stringify(run(scenario)));
29	};
30	
31	main();
