38	const countByType = (items: Item[]): Map<string, number> => {
39	  const counts = new Map<string, number>();
40	  for (const item of items) {
41	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
42	  }
43	  return counts;
44	};
45	
46	const componentsBase = (components: Item[]): number => {
47	  let total = 0;
48	  for (const [type, count] of countByType(components)) {
49	    total += count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * BASE_PREMIUMS[type];
50	  }
51	  return total;
52	};
53	
54	const mainItemsBase = (items: Item[]): number =>
55	  items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
56	
57	const itemSurcharges = (item: Item): number => {
58	  const base = BASE_PREMIUMS[item.type];
59	  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
60	  const highEnchant = (item.enchantment ?? 0) >= HIGH_ENCHANT_THRESHOLD ? base * HIGH_ENCHANT_SURCHARGE_RATE : 0;
61	  return curse + highEnchant;
