72	  const components = step.items.filter((i) => COMPONENT_TYPES.has(i.type));
73	
74	  const policyBase = mainItemsBase(mainItems) + componentsBase(components);
75	  const firstInsurance = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
76	  const surcharges = mainItems.reduce((sum, item) => sum + itemSurcharges(item), 0);
77	  const loyalty = loyaltyDiscount(policyBase, customer);
78	  const followUp = followUpDiscount(policyBase, isFollowUp);
