103	
104	const damagePayout = (damage: Damage, policyItems: Item[]): number => {
105	  const item = policyItems.find((i) => i.type === damage.itemType);
106	  return Math.max(0, damage.amount * reimbursementRate(item) - DEDUCTIBLE);
107	};
108	
109	const claimResult = (step: ClaimStep, policyItems: Item[], availableCap: number): ClaimResult => {
110	  const rawPayout = step.incident.damages.reduce(
111	    (sum, d) => sum + damagePayout(d, policyItems),
112	    0,
113	  );
114	  const cappedPayout = Math.min(rawPayout, availableCap);
115	  const payout = Math.floor(cappedPayout);
116	  return { payout, remainingCap: availableCap - payout };
