122	    throw new Error(`step ${step.policy} is not a quote`);
123	  }
124	  return policyStep.items;
125	};
126	
127	const initialCap = (policyItems: Item[]): number =>
128	  insuranceSum(policyItems) * CAP_MULTIPLIER;
