130	const processClaim = (
131	  step: ClaimStep,
132	  scenario: Scenario,
133	  remainingCapByPolicy: Map<number, number>,
134	): ClaimResult => {
135	  const policyItems = policyItemsFor(step, scenario.steps);
136	  const availableCap = remainingCapByPolicy.get(step.policy) ?? initialCap(policyItems);
137	  const result = claimResult(step, policyItems, availableCap);
138	  remainingCapByPolicy.set(step.policy, result.remainingCap);
139	  return result;
140	};
